#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int P; scanf("%d", &P);
        int ans = -1;
        for(int b=0; b<=10 && b*100<=P; ++b){
            int a = P - 100*b;
            if(a>=0 && a+b<=10){
                ans = a + b;
                break;
            }
        }
        printf("%d\n", ans);
    }
    return 0;
}

