code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        P = int(next(it))
        ans = -1
        for b in range(0, 11):
            if b*100 > P:
                break
            a = P - 100*b
            if a >= 0 and a + b <= 10:
                ans = a + b
                break
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

